import { nextMonster } from '../game/gameLogic'
import { actionType } from './actionType'

const initState = nextMonster()

export const currentMonsterReducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.damageMonster: {
      return damageMonster(state, action)
    }
    case actionType.handleMonsterKilledEvent: {
      return handleMonsterKilledEvent(state, action)
    }
    default: {
      return state
    }
  }
}

export const damageMonster = (state, action) => {
  const health = state.health - action.data.damage
  return {
    ...state,
    health,
  }
}

export const handleMonsterKilledEvent = (state, action) => {
  const monster = nextMonster()
  monster.health = Math.ceil(monster.health + (action.data.level - 1) * 10.6)
  return {
    ...monster,
  }
}
