import React from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { actionCreator } from './redux/actionCreator'
import { MonsterPanel } from './component/MonsterPanel'
import { LevelPanel } from './component/LevelPanel'
import { PlayerPanel } from './component/PlayerPanel'
import { MonsterDataPanel } from './component/MonsterDataPanel'

function App () {
  const dispatch = useDispatch()
  const state = useSelector(state => state)

  const handleUpgradeClick = () => {
    if (state.player.gold >= state.player.upgradeCost) {
      dispatch(actionCreator.upgrade())
    }
  }

  const handleAttackClick = () => {
    dispatch(actionCreator.damageMonster(state.player.damage))
  }

  return (
    <div>
      <h1>Idle Monster</h1>

      <MonsterPanel/>

      <LevelPanel/>

      <PlayerPanel/>

      <button
        onClick={handleUpgradeClick}
        disabled={state.player.gold < state.player.upgradeCost}
      >
        Upgrade
      </button>
      <button
        onClick={handleAttackClick}
      >
        Attack
      </button>

      <MonsterDataPanel/>

    </div>
  )
}

export default App
