import React from 'react'
import { useSelector } from 'react-redux'

export const MonsterPanel = () => {
  const state = useSelector(state => state)

  return (
    <fieldset>
      <legend>Monster</legend>
      <table>
        <thead>
        <tr>
          <th>{`Monster Name`}</th>
          <th>{`Monster Health`}</th>
        </tr>
        </thead>
        <tbody>
        <tr>
          <td>{state.currentMonster.name}</td>
          <td>{state.currentMonster.health}</td>
        </tr>
        </tbody>
      </table>
    </fieldset>
  )
}
