import { actionType } from './actionType'
import { actionCreator } from './actionCreator'

const initState = {
  damage: 1,
  gold: 0,
  level: 1,
  levelKillAmount: 0,
  levelKillAmountRequire: 10,
  upgradeCost: 1,
}

export const playerReducer = (state = initState, action) => {
  switch (action.type) {
    case actionType.upgrade: {
      return upgrade(state, action)
    }
    case actionType.handleMonsterKilledEvent: {
      return handleMonsterKilledEvent(state, action)
    }
    case actionType.handleLevelUpgradeEvent: {
      return handleLevelUpgradeEvent(state, action)
    }
    default: {
      return state
    }
  }
}

export const upgrade = (state, action) => {
  const damage = state.damage + 1
  const gold = state.gold - state.upgradeCost
  const upgradeCost = Math.ceil(state.upgradeCost * 1.46)
  return {
    ...state,
    damage,
    gold,
    upgradeCost,
  }
}

export const handleMonsterKilledEvent = (state, action) => {
  state = incrementGold(state, actionCreator.incrementGold(
    Math.round(state.level * 1.33),
  ))
  state = incrementLevelKillAmount(state, action)
  return state
}

export const incrementGold = (state, action) => {
  const gold = state.gold + action.data.amount
  return {
    ...state,
    gold,
  }
}

export const incrementLevelKillAmount = (state, action) => {
  const levelKillAmount = state.levelKillAmount + 1
  return {
    ...state,
    levelKillAmount,
  }
}

export const handleLevelUpgradeEvent = (state, action) => {
  if (state.levelKillAmount < state.levelKillAmountRequire) {
    return state
  }

  const levelKillAmount = 0
  const level = state.level + 1
  return {
    ...state,
    level,
    levelKillAmount,
  }
}
