import React from 'react'
import { useSelector } from 'react-redux'

export const PlayerPanel = () => {
  const state = useSelector(state => state)

  return (
    <fieldset>
      <legend>Player</legend>
      <table>
        <thead>
        <tr>
          <th>{`Gold`}</th>
          <th>{`Upgrade Cost`}</th>
          <th>{`Damage`}</th>
        </tr>
        </thead>
        <tbody>
        <tr>
          <td>{state.player.gold}</td>
          <td>{state.player.upgradeCost}</td>
          <td>{state.player.damage}</td>
        </tr>
        </tbody>
      </table>
    </fieldset>
  )
}
